// Source: EnergyPlus/src/EnergyPlus/General.cc — SafeDivide()
#include <cmath>
double ep_safe_divide(double a, double b) {
    constexpr double SMALL = 1e-10;
    if (std::abs(b) >= SMALL) return a / b;
    return a / std::copysign(SMALL, b == 0.0 ? 1.0 : b);
}

