import math

fn ep_safe_divide(a: Float64, b: Float64) -> Float64:
    var SMALL: Float64 = 1e-10
    if abs(b) >= SMALL:
        return a / b
    var sign_b = 1.0 if b >= 0.0 else -1.0
    return a / (SMALL * sign_b)
